return [{
  json: {
    api_key_id: 'TUTAJ_KEY_ID',
    private_key_pem: `-----BEGIN RSA PRIVATE KEY-----
TUTAJ_KLUCZ_PEM
-----END RSA PRIVATE KEY-----`,
    kalshi_base: 'https://api.elections.kalshi.com/trade-api/v2',
    claude_api_key: 'TUTAJ_CLAUDE_KEY',
    dry_run: true
  }
}];

const crypto = require('crypto');
const config = $input.first().json;

// Series tickers to scan - each becomes a separate API call
const series = [
  // Crypto daily
  'KXBTCD', 'KXETHD', 'KXSOLD', 'KXDOGED', 'KXXRPD',
  // Crypto weekly/other
  'KXBTC', 'KXETH', 'KXSOL',
  // Sports
  'KXNBAGAME', 'KXNBASPREAD', 'KXNBATOTAL', 'KXNBAPTS',
  'KXNHLGAME', 'KXNHLSPREAD', 'KXNHLTOTAL',
  'KXNCAAMBGAME', 'KXNCAAMBSPREAD',
  'KXMLBGAME', 'KXEPLGAME', 'KXLALIGAGAME',
  'KXUFCFIGHT', 'KXPGA',
  // Economics
  'KXFED', 'KXCPI', 'KXGDP', 'KXJOBLESS', 'KXNONFARM',
  'KXGASPRICE', 'KXRETAIL',
  // Financials
  'KXINXD', 'KXINX',
  'KXNASD', 'KXNAS',
  'KXWTI', 'KXGOLD',
  'KXEURUSD', 'KXUSDJPY',
  // Climate
  'KXHIGHNY', 'KXLOWNY', 'KXHIGHCHI',
  // Politics
  'KXTRUMP', 'KXAPPROVAL',
  // Companies
  'KXAAPL', 'KXGOOG', 'KXTSLA', 'KXNVDA', 'KXMSFT',
  // Tech & Science
  'KXAI', 'KXTIKTOK'
];

const path = '/trade-api/v2/markets';
const method = 'GET';

// Generate one signed item per series
const items = series.map(s => {
  const ts = Date.now().toString();
  const msg = ts + method + path;
  const sign = crypto.createSign('RSA-SHA256');
  sign.update(msg);
  sign.end();
  const sig = sign.sign({
    key: config.private_key_pem,
    padding: crypto.constants.RSA_PKCS1_PSS_PADDING,
    saltLength: crypto.constants.RSA_PSS_SALTLEN_DIGEST,
  }).toString('base64');

  return {
    json: {
      series_ticker: s,
      api_key_id: config.api_key_id,
      kalshi_base: config.kalshi_base,
      timestamp: ts,
      signature: sig,
      claude_api_key: config.claude_api_key,
      private_key_pem: config.private_key_pem,
      dry_run: config.dry_run
    }
  };
});

return items;

// Merge all series + sign balance/positions
const crypto = require('crypto');
const allItems = $input.all();
const config = $('⚙️ Config').first().json;
let allMarkets = [];

for (const item of allItems) {
  const markets = item.json.markets || [];
  allMarkets = allMarkets.concat(markets);
}

function signPath(method, path) {
  const ts = Date.now().toString();
  const s = crypto.createSign('RSA-SHA256');
  s.update(ts + method + path);
  s.end();
  return {
    ts,
    sig: s.sign({
      key: config.private_key_pem,
      padding: crypto.constants.RSA_PKCS1_PSS_PADDING,
      saltLength: crypto.constants.RSA_PSS_SALTLEN_DIGEST,
    }).toString('base64')
  };
}

const balSign = signPath('GET', '/trade-api/v2/portfolio/balance');
const posSign = signPath('GET', '/trade-api/v2/portfolio/positions');

return [{ json: {
  markets: allMarkets,
  total: allMarkets.length,
  bal_ts: balSign.ts,
  bal_sig: balSign.sig,
  pos_ts: posSign.ts,
  pos_sig: posSign.sig,
  api_key_id: config.api_key_id
} }];

// Process + Filter all markets
const config = $('⚙️ Config').first().json;
const marketsRaw = $('🔀 Merge Markets').first().json;
const balanceRaw = $('💰 Get Balance').first().json;
const positionsRaw = $('📦 Get Positions').first().json;

const markets = marketsRaw.markets || [];
const balance = balanceRaw.balance || 0;
const positions = positionsRaw.market_positions || [];

if (balance < 200) {
  return [{ json: { ready: false, reason: `Balance: $${(balance/100).toFixed(2)} (min $2)` } }];
}

const filtered = markets
  .filter(m => {
    if (m.ticker && m.ticker.includes('KXMVE')) return false;
    if (m.mve_collection_ticker) return false;
    if (m.is_provisional === true) return false;

    const yesAsk = parseFloat(m.yes_ask_dollars || '0');
    if (yesAsk <= 0) return false;
    if (yesAsk <= 0.05 || yesAsk >= 0.95) return false;

    const expTime = m.expected_expiration_time || m.close_time || m.expiration_time;
    if (!expTime) return false;
    const hoursToExp = (new Date(expTime) - new Date()) / 3600000;
    if (hoursToExp <= 0 || hoursToExp > 168) return false;

    return true;
  })
  .sort((a, b) => parseFloat(b.volume_fp || '0') - parseFloat(a.volume_fp || '0'))
  .slice(0, 20)
  .map(m => ({
    ticker: m.ticker,
    title: m.title || m.subtitle || m.ticker,
    category: m.category || m.event_ticker || 'unknown',
    yes_ask: Math.round(parseFloat(m.yes_ask_dollars || '0') * 100),
    yes_bid: Math.round(parseFloat(m.yes_bid_dollars || '0') * 100),
    no_ask: Math.round(parseFloat(m.no_ask_dollars || '0') * 100),
    no_bid: Math.round(parseFloat(m.no_bid_dollars || '0') * 100),
    last_price: Math.round(parseFloat(m.last_price_dollars || '0') * 100),
    volume: parseFloat(m.volume_fp || '0'),
    volume_24h: parseFloat(m.volume_24h_fp || '0'),
    open_interest: parseFloat(m.open_interest_fp || '0'),
    close_time: m.expected_expiration_time || m.close_time,
    spread: Math.round((parseFloat(m.yes_ask_dollars || '0') - parseFloat(m.yes_bid_dollars || '0')) * 100)
  }));

const openExp = positions.reduce((s, p) => s + Math.abs(p.market_exposure || 0), 0);
const slots = 5 - positions.length;

if (filtered.length === 0 || slots <= 0) {
  return [{ json: { ready: false, reason: filtered.length === 0 ? `No markets pass filters (${markets.length} scanned)` : 'Max 5 positions' } }];
}

return [{
  json: {
    ready: true,
    markets: filtered,
    market_count: filtered.length,
    total_scanned: markets.length,
    balance_cents: balance,
    balance_usd: (balance / 100).toFixed(2),
    positions: positions,
    position_count: positions.length,
    open_exposure_cents: openExp,
    slots_available: slots,
    api_key_id: config.api_key_id,
    private_key_pem: config.private_key_pem,
    kalshi_base: config.kalshi_base,
    dry_run: config.dry_run,
    claude_api_key: config.claude_api_key,
    scan_timestamp: new Date().toISOString()
  }
}];

const data = $input.first().json;

const marketList = data.markets.map((m, i) => {
  const h = m.close_time ? Math.round((new Date(m.close_time) - new Date()) / 3600000) + 'h' : '?';
  return `[${i+1}] ${m.ticker}\n  ${m.title}\n  YES: ${m.yes_bid}c/${m.yes_ask}c (last ${m.last_price}c) | NO: ${m.no_bid}c/${m.no_ask}c\n  Spread:${m.spread}c Vol:${m.volume} OI:${m.open_interest} Closes:${h}`;
}).join('\n\n');

const posList = data.positions.length > 0
  ? data.positions.map(p => `${p.ticker}: ${p.position} contracts`).join('\n')
  : 'None';

const avail = data.balance_cents - data.open_exposure_cents;

const prompt = `PORTFOLIO: $${data.balance_usd} | Exposure: ${data.open_exposure_cents}c | Free: ${avail}c | Positions: ${data.position_count}/5 (${data.slots_available} slots)\n${posList}\n\nRULES: Max 1-2 contracts, max 50c/trade, min 10pp edge, closing <7 days\n\nMARKETS (${data.market_count}/${data.total_scanned}):\n\n${marketList}\n\nFind >10pp mispricings. JSON only.`;

return [{
  json: {
    prompt,
    api_key_id: data.api_key_id,
    private_key_pem: data.private_key_pem,
    kalshi_base: data.kalshi_base,
    dry_run: data.dry_run,
    claude_api_key: data.claude_api_key,
    balance_cents: data.balance_cents,
    scan_timestamp: data.scan_timestamp
  }
}];

const response = $input.first().json;
const prev = $('🧠 Build Prompt').first().json;

let text = '';
try {
  if (response.content && Array.isArray(response.content)) {
    text = response.content.filter(c => c.type === 'text').map(c => c.text).join('');
  }
} catch (e) {
  return [{ json: { execute: false, has_trades: false, error: 'Parse failed', scan_timestamp: prev.scan_timestamp, dry_run: prev.dry_run } }];
}

let analysis;
try {
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch (e) {
  const match = text.match(/\{[\s\S]*\}/);
  if (match) { try { analysis = JSON.parse(match[0]); } catch (e2) {} }
}

if (!analysis || !analysis.trades || analysis.trades.length === 0) {
  return [{ json: {
    execute: false, has_trades: false,
    scan_summary: analysis?.scan_summary || {},
    portfolio_notes: analysis?.portfolio_notes || 'No opportunities',
    scan_timestamp: prev.scan_timestamp, dry_run: prev.dry_run
  }}];
}

const valid = analysis.trades
  .filter(t => Math.abs(t.edge_pp) >= 10 && t.ticker)
  .map(t => {
    t.contracts = Math.min(t.contracts || 1, 2);
    t.total_cost_cents = t.contracts * t.limit_price_cents;
    if (t.total_cost_cents > 50) { t.contracts = 1; t.total_cost_cents = t.limit_price_cents; }
    if (t.total_cost_cents > 50) return null;
    return t;
  })
  .filter(Boolean);

if (valid.length === 0) {
  return [{ json: {
    execute: false, has_trades: false,
    scan_summary: analysis.scan_summary,
    portfolio_notes: analysis.portfolio_notes || 'Trades failed validation',
    scan_timestamp: prev.scan_timestamp, dry_run: prev.dry_run
  }}];
}

const best = valid.sort((a, b) => Math.abs(b.edge_pp) - Math.abs(a.edge_pp))[0];
const side = best.action === 'BUY_YES' ? 'yes' : 'no';

const orderBody = {
  ticker: best.ticker,
  action: 'buy',
  side: side,
  count: best.contracts,
  type: 'limit',
  client_order_id: `micro-${Date.now()}-${best.ticker.slice(-6)}`,
  expiration_ts: Math.floor(Date.now() / 1000) + 7200
};
if (side === 'yes') orderBody.yes_price = best.limit_price_cents;
else orderBody.no_price = best.limit_price_cents;

return [{ json: {
  execute: !prev.dry_run,
  has_trades: true,
  dry_run: prev.dry_run,
  trade: best,
  order_body: orderBody,
  scan_summary: analysis.scan_summary,
  portfolio_notes: analysis.portfolio_notes,
  api_key_id: prev.api_key_id,
  private_key_pem: prev.private_key_pem,
  kalshi_base: prev.kalshi_base,
  scan_timestamp: prev.scan_timestamp
}}];

const crypto = require('crypto');
const data = $input.first().json;
const ts = Date.now().toString();
const path = '/trade-api/v2/portfolio/orders';
const msg = ts + 'POST' + path;
const sign = crypto.createSign('RSA-SHA256');
sign.update(msg);
sign.end();
const sig = sign.sign({
  key: data.private_key_pem,
  padding: crypto.constants.RSA_PKCS1_PSS_PADDING,
  saltLength: crypto.constants.RSA_PSS_SALTLEN_DIGEST,
}).toString('base64');

return [{ json: { ...data, order_timestamp: ts, order_signature: sig } }];
